sql:
SELECT blog_id, plant_id, blog_text, publish_date 
FROM plant_blogs
WHERE blog_title = 'Indoor Plant Care';

SELECT plants.name, plant_types.type_name, plants.description
FROM plants
JOIN plant_types ON plants.type_id = plant_types.type_id;

SELECT COUNT(DISTINCT user_id) 
FROM plant_questions 
WHERE plant_id = 1;

SELECT care_instructions
FROM plant_care
WHERE plant_id = 1;

SELECT plant_id, AVG(rating) AS Avg_Rating
FROM plant_reviews
GROUP BY plant_id;
